import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"汤姆·墨菲（Tom Murphy）","description":"","frontmatter":{},"headers":[],"relativePath":"04_people/Tom_Murphy.md","filePath":"04_people/Tom_Murphy.md"}'),o={name:"04_people/Tom_Murphy.md"};function h(i,a,d,u,n,s){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="汤姆·墨菲-tom-murphy" tabindex="-1">汤姆·墨菲（Tom Murphy） <a class="header-anchor" href="#汤姆·墨菲-tom-murphy" aria-label="Permalink to &quot;汤姆·墨菲（Tom Murphy）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>全名</td><td>Thomas S. Murphy</td></tr><tr><td>公司</td><td><a href="./../03_公司库/首都城市ABC.html">首都城市/ABC</a></td></tr><tr><td>职位</td><td>CEO</td></tr><tr><td>任期</td><td>1966-1990年代</td></tr></tbody></table><h2 id="职业生涯" tabindex="-1">职业生涯 <a class="header-anchor" href="#职业生涯" aria-label="Permalink to &quot;职业生涯&quot;">​</a></h2><h3 id="首都城市通信" tabindex="-1">首都城市通信 <a class="header-anchor" href="#首都城市通信" aria-label="Permalink to &quot;首都城市通信&quot;">​</a></h3><ul><li>1966年成为CEO</li><li>将小电视台组合发展为大型媒体集团</li><li>1985年以35亿美元收购ABC（美国广播公司）</li></ul><h3 id="管理成就" tabindex="-1">管理成就 <a class="header-anchor" href="#管理成就" aria-label="Permalink to &quot;管理成就&quot;">​</a></h3><ol><li>从小型电视台发展成大型媒体集团</li><li>成功收购并整合ABC</li><li>成本控制极致</li><li>资本配置能力出色</li></ol><h2 id="管理风格" tabindex="-1">管理风格 <a class="header-anchor" href="#管理风格" aria-label="Permalink to &quot;管理风格&quot;">​</a></h2><h3 id="核心特点" tabindex="-1">核心特点 <a class="header-anchor" href="#核心特点" aria-label="Permalink to &quot;核心特点&quot;">​</a></h3><ol><li><strong>成本控制</strong>：极致削减成本但不损害质量</li><li><strong>人才管理</strong>：任用优秀经理人并给予自主权</li><li><strong>资本配置</strong>：回购股票、收购资产</li><li><strong>诚信经营</strong>：从不欺骗股东或合作伙伴</li></ol><h3 id="与dan-burke搭档" tabindex="-1">与Dan Burke搭档 <a class="header-anchor" href="#与dan-burke搭档" aria-label="Permalink to &quot;与Dan Burke搭档&quot;">​</a></h3><ul><li>两人被称为&quot;管理两连击&quot;</li><li>Murphy负责大局，Burke负责运营</li><li>两人配合默契</li></ul><h2 id="巴菲特评价摘录" tabindex="-1">巴菲特评价摘录 <a class="header-anchor" href="#巴菲特评价摘录" aria-label="Permalink to &quot;巴菲特评价摘录&quot;">​</a></h2><h3 id="_1985年股东信" tabindex="-1">1985年股东信 <a class="header-anchor" href="#_1985年股东信" aria-label="Permalink to &quot;1985年股东信&quot;">​</a></h3><blockquote><p>&quot;Tom Murphy和Dan Burke是美国上市公司最好的管理层。&quot;</p></blockquote><blockquote><p>&quot;他们在运营能力和资本配置能力上都非常出色。&quot;</p></blockquote><blockquote><p>&quot;这是一个管理层的&#39;两连击&#39;：他们知道如何收购正确类型的企业，也知道如何运营它们。&quot;</p></blockquote><blockquote><p>&quot;我愿意把女儿嫁给Tom Murphy。&quot;（开玩笑）</p></blockquote><h3 id="后续评价" tabindex="-1">后续评价 <a class="header-anchor" href="#后续评价" aria-label="Permalink to &quot;后续评价&quot;">​</a></h3><blockquote><p>&quot;Tom Murphy是我认识的最优秀的管理者之一。他的诚信和能力都是顶级的。&quot; —— 巴菲特多次提及</p></blockquote><h2 id="与伯克希尔关系" tabindex="-1">与伯克希尔关系 <a class="header-anchor" href="#与伯克希尔关系" aria-label="Permalink to &quot;与伯克希尔关系&quot;">​</a></h2><table tabindex="0"><thead><tr><th>事件</th><th>内容</th></tr></thead><tbody><tr><td>1977年</td><td>巴菲特开始持有首都城市股票</td></tr><tr><td>1985年</td><td>收购ABC，巴菲特帮助融资5.175亿美元</td></tr><tr><td>投资特点</td><td>巴菲特签署不寻常协议，投票权委托给Murphy</td></tr></tbody></table><h2 id="影响力" tabindex="-1">影响力 <a class="header-anchor" href="#影响力" aria-label="Permalink to &quot;影响力&quot;">​</a></h2><ul><li>巴菲特媒体投资的重要合作伙伴</li><li>首都城市成为伯克希尔长期投资典范</li><li>展示了优秀管理层对企业价值的决定性作用</li></ul><h2 id="在股东信中的年份" tabindex="-1">在股东信中的年份 <a class="header-anchor" href="#在股东信中的年份" aria-label="Permalink to &quot;在股东信中的年份&quot;">​</a></h2><p>1985, 1986, 1987</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/首都城市ABC.html">首都城市/ABC</a> - 管理的企业</li><li><a href="./丹·伯克.html">丹·伯克</a> - 搭档</li><li><a href="./凯瑟琳·格雷厄姆.html">凯瑟琳·格雷厄姆</a> - 同为媒体CEO</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',31)])])}const q=t(o,[["render",h]]);export{b as __pageData,q as default};
